// Import required modules
const express = require('express');
const app = express();
const server = require('http').createServer(app);
const io = require('socket.io')(server);

// Set up Express.js middleware to parse JSON bodies of incoming requests
app.use(express.json());

// In-memory store for player data (for demonstration purposes only)
let players = {};

// Handle new player connections
io.on('connection', socket => {
    console.log('New connection established');

    // Handle player disconnections
    socket.on('disconnect', () => {
        console.log('Connection lost');
        deletePlayer(socket.handshake.query.username);
    });

    // Handle score submissions from client
    socket.on('score', (username, score) => {
        if (!players[username]) return;

        players[username].score = score;
        io.emit('scoresUpdate', players);

        saveToDatabase(players); // Save to database (async operation)
    });
});

// Function to add new player to in-memory store
function addPlayer(username) {
    if (players[username]) return;

    const playerData = { username, score: 0 };
    players[username] = playerData;
}

// Function to delete a player from the in-memory store
function deletePlayer(username) {
    if (!players[username]) return;

    delete players[username];
}

// Save player data to database (async operation)
function saveToDatabase(players) {
    // Replace with actual implementation for your database
    setTimeout(() => console.log('Players saved to database'), 0);
}

// Serve static files from the public directory
app.use(express.static(__dirname + '/public'));

// Start server
server.listen(3000, () => {
    console.log('Server listening on port 3000');
});